#!/usr/bin/env python3 # -*- coding: utf-8 -*- """ Direct email verification — no MCP needed. Uses local check-if-email-exists Docker container (Reacher).  Requirements:     Docker running with reacherhq/backend on port 8080.     Start: docker run -d -p 8080:8080 --name reacher reacherhq/backend:latest  Usage:     python verify_email_direct.py test@example.com     python verify_email_direct.py --batch emails.txt --output results.csv     python verify_email_direct.py --server """  import sys import json import csv import time import argparse import urllib.request import urllib.error from http.server import HTTPServer, BaseHTTPRequestHandler  REACHER_URL = "http://localhost:8080/v0/check_email" DEFAULT_DELAY = 0.3  # seconds between requests to avoid overwhelming Docker   def check_reacher(email, timeout=15):     """     Check a single email via Reacher Docker API.      Returns dict with keys:         email, is_reachable, syntax_valid, mx_valid, smtp_valid,         has_catch_all, is_disposable, is_role_account, error (if any)     """     try:         url = f"{REACHER_URL}?email={urllib.request.quote(email)}"         resp = urllib.request.urlopen(url, timeout=timeout)         data = json.loads(resp.read())          input_data = data.get("input", email)         syntax = data.get("syntax", {})         mx = data.get("mx", {})         smtp = data.get("smtp", {})         misc = data.get("misc", {})          return {             "email": input_data,             "is_reachable": data.get("is_reachable", "unknown"),             "syntax_valid": syntax.get("is_valid", False) if isinstance(syntax, dict) else bool(syntax),             "mx_valid": mx.get("accepts_mail", False) if isinstance(mx, dict) else False,             "smtp_valid": smtp.get("can_connect_smtp", False) if isinstance(smtp, dict) else False,             "has_catch_all": misc.get("is_catch_all", False) if isinstance(misc, dict) else False,             "is_disposable": misc.get("is_disposable", False) if isinstance(misc, dict) else False,             "is_role_account": misc.get("is_role_account", False) if isinstance(misc, dict) else False,             "error": None         }     except urllib.error.URLError as e:         return {             "email": email,             "is_reachable": "unknown",             "error": f"Docker/Reacher unavailable: {e.reason}. Start with: docker run -d -p 8080:8080 --name reacher reacherhq/backend:latest"         }     except Exception as e:         return {"email": email, "is_reachable": "unknown", "error": str(e)}   def check_health():     """Verify Reacher is running."""     try:         resp = urllib.request.urlopen("http://localhost:8080/health", timeout=5)         return resp.read().decode()[:200]     except Exception as e:         return f"Reacher not reachable: {e}"   def batch_verify(emails, delay=DEFAULT_DELAY):     """Verify a list of emails with rate limiting."""     results = []     total = len(emails)     for i, email in enumerate(emails):         email = email.strip()         if not email or "@" not in email:             results.append({"email": email, "is_reachable": "invalid", "error": "Bad format"})             print(f"[{i+1}/{total}] {email}: SKIP (bad format)")             continue          r = check_reacher(email)         results.append(r)         status = r.get("is_reachable", "error")         icon = "✓" if status == "valid" else "✗" if status == "invalid" else "?"         print(f"[{i+1}/{total}] {email}: {icon} {status}")          if i < total - 1:             time.sleep(delay)     return results   def save_results(results, output_path):     """Save results to CSV."""     fieldnames = [         "email", "is_reachable", "syntax_valid", "mx_valid",         "smtp_valid", "has_catch_all", "is_disposable",         "is_role_account", "error"     ]     with open(output_path, "w", newline="", encoding="utf-8-sig") as f:         w = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")         w.writeheader()         for r in results:             w.writerow({k: r.get(k, "") for k in fieldnames})      # Summary     counts = {}     for r in results:         s = r.get("is_reachable", "unknown")         counts[s] = counts.get(s, 0) + 1     print(f"\nSaved to {output_path}")     print(f"Summary: {counts}")   # ---- HTTP Server Mode ---- class ReacherProxyHandler(BaseHTTPRequestHandler):     """HTTP proxy that wraps Reacher API for MCP-like access."""      def log_message(self, format, *args):         """Suppress noisy logs."""         pass      def do_GET(self):         if self.path == "/health":             self._json_response(200, {"status": "ok", "backend": "reacher-proxy"})             return          if "/check_email" in self.path:             email = ""             if "email=" in self.path:                 email = self.path.split("email=")[-1].split("&")[0]                 email = urllib.parse.unquote(email)             if email:                 result = check_reacher(email, timeout=10)                 self._json_response(200, result)             else:                 self._json_response(400, {"error": "Missing ?email= parameter"})             return          self._json_response(404, {"error": "Not found. Use /health or /check_email?email=test@example.com"})      def _json_response(self, code, data):         self.send_response(code)         self.send_header("Content-Type", "application/json; charset=utf-8")         self.send_header("Access-Control-Allow-Origin", "*")         self.end_headers()         self.wfile.write(json.dumps(data, indent=2, ensure_ascii=False).encode("utf-8"))   def run_server(host="127.0.0.1", port=8081):     """Run an HTTP server that proxies to Reacher Docker."""     server = HTTPServer((host, port), ReacherProxyHandler)     print(f"Reacher proxy server running on http://{host}:{port}")     print(f"  Test: curl http://{host}:{port}/check_email?email=test@gmail.com")     print(f"  Press Ctrl+C to stop.")     try:         server.serve_forever()     except KeyboardInterrupt:         print("\nShutting down...")         server.shutdown()   # ---- CLI ---- def main():     parser = argparse.ArgumentParser(         description="Direct email verification via Reacher Docker",         formatter_class=argparse.RawDescriptionHelpFormatter,         epilog=""" Examples:   python verify_email_direct.py test@gmail.com   python verify_email_direct.py --batch emails.txt --output results.csv   python verify_email_direct.py --server   python verify_email_direct.py --health         """     )     parser.add_argument("email", nargs="?", help="Single email to verify")     parser.add_argument("--batch", help="Input file: one email per line")     parser.add_argument("--output", default="results.csv", help="Output CSV path")     parser.add_argument("--delay", type=float, default=DEFAULT_DELAY,                         help=f"Delay between batch requests in seconds (default: {DEFAULT_DELAY})")     parser.add_argument("--server", action="store_true", help="Run as HTTP proxy server")     parser.add_argument("--port", type=int, default=8081, help="Server port (default: 8081)")     parser.add_argument("--health", action="store_true", help="Check if Reacher is running")     args = parser.parse_args()      if args.health:         print(check_health())         return      if args.server:         run_server(port=args.port)         return      if args.batch:         try:             with open(args.batch, encoding="utf-8") as f:                 emails = [l.strip() for l in f if l.strip()]         except FileNotFoundError:             print(f"File not found: {args.batch}")             sys.exit(1)         if not emails:             print("No emails found in file.")             sys.exit(1)         print(f"Verifying {len(emails)} emails (delay: {args.delay}s)...\n")         results = batch_verify(emails, delay=args.delay)         save_results(results, args.output)     elif args.email:         result = check_reacher(args.email)         print(json.dumps(result, indent=2, ensure_ascii=False))         # Quick verdict         status = result.get("is_reachable", "unknown")         if status == "valid":             print(f"\n✓ {args.email} looks good to send.")         elif status == "invalid":             print(f"\n✗ {args.email} is not deliverable.")         else:             print(f"\n? {args.email}: {status} — verify manually if important.")     else:         parser.print_help()         print("\nQuick start:")         print("  1. Ensure Docker Reacher is running: docker run -d -p 8080:8080 --name reacher reacherhq/backend:latest")         print("  2. Verify an email: python verify_email_direct.py test@gmail.com")   if __name__ == "__main__":     main()